import { ArrowLeftIcon, Contact2Icon, HouseIcon, PhilippinePesoIcon } from "lucide-react";
import Link from "next/link";
import React from "react";

const page = () => {
  return (
    <>
      <div className="">
        <div className="p-5">
          <Link href={"/cart"}>
            <ArrowLeftIcon />
          </Link>
          <p className="text-center">Checkout</p>
        </div>
        <div className="max-w-full w-[900] mx-auto border-1 border-[#000]">
          <div className="flex flex-row py-2 px-2 m-2 rounded-md bg-[#fff]">
            <HouseIcon size={35} color="#1e6b55" />
            <div className="flex flex-col mx-2">
              <p className="sm:text-sm md:text-md font-semibold">Store Name</p>
              <p className="text-xs text-[#5f5f5f] uppercase">
                puregold minimart - ho
              </p>
            </div>
          </div>
          <div className="flex flex-row py-2 px-2 m-2 rounded-md bg-[#fff]">
            <Contact2Icon size={35} color="#1e6b55" />
            <div className="flex flex-col mx-2">
              <p className="sm:text-sm md:text-md font-semibold">Contact Person</p>
              <p className="text-xs text-[#5f5f5f] uppercase">
                Matthew Emmanuel Aniban, +63929
              </p>
            </div>
          </div>
          <div className="flex flex-row py-2 px-2 m-2 rounded-md bg-[#fff]">
            <PhilippinePesoIcon size={35} color="#1e6b55" />
            <div className="flex flex-col mx-2">
              <p className="sm:text-sm md:text-md font-semibold">Store Name</p>
              
              <p className="text-xs text-[#AF3E3E] uppercase">
                tap to select payment method
              </p>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default page;
